document.addEventListener("DOMContentLoaded",()=>{const e=document.querySelector(".toc-content");if(!e)return;const t=Array.from(document.querySelectorAll("h2[id], h3[id], h2 .anchor, h3 .anchor"));if(!t.length)return;const s=e.querySelectorAll("a"),o=t=>{s.forEach(e=>e.classList.remove("active"));const n=e.querySelector(`a[href="#${CSS.escape(t)}"]`);n?.classList.add("active")},n=()=>{let e=null;for(const n of t)n.getBoundingClientRect().top<=120&&(e=n.id);e&&o(e)};window.addEventListener("scroll",n,{passive:!0}),n()})